function syncCurrentBlock(){
  if(!state.practiceActive)return;
  if(state.currentBlockId){
    const found=state.blocks.findIndex(b=>b.id===state.currentBlockId);
    if(found>=0)state.currentIndex=found;
  }
  if(state.currentIndex>=state.blocks.length)state.currentIndex=Math.max(0,state.blocks.length-1);
  state.currentBlockId=state.blocks[state.currentIndex]?.id||null;
}
