let practiceQueue=[];let drillLibrary=[];let pendingArchiveSnapshot=null;
function loadCoachKnowledge(){try{practiceQueue=JSON.parse(localStorage.getItem('wpp-practice-queue')||'[]');drillLibrary=JSON.parse(localStorage.getItem('wpp-drill-library')||'[]')}catch{practiceQueue=[];drillLibrary=[]}}
